const parseJsonSchema = (
	jsonSchema: JsonSchemaOrBoolean,
	context: ParseContext
): type.Any => {
	if (typeof jsonSchema === "boolean")
		return jsonSchema ? type.unknown : type.never
	if (Array.isArray(jsonSchema)) return parseAnyOfJsonSchema(jsonSchema)

	const schema = jsonSchema as JsonSchema & Record<string, unknown>
	if ("$ref" in schema) return parseRef(schema.$ref, context)

	if (!("if" in schema) && ("then" in schema || "else" in schema))
		return type.unknown
